+      break;
+    case LayoutKind::NULLABLE_ATOMIC_FLAT:
+      return has_nullable_atomic_layout();
+      break;
+    case LayoutKind::NULLABLE_NON_ATOMIC_FLAT:
+      return has_nullable_non_atomic_layout();
+      break;
+    case LayoutKind::BUFFERED:
+      return true;
+      break;
+    default:
+      ShouldNotReachHere();
+  }
